class Solution:
    def minSwaps(self, nums):
        n = len(nums)
        par = [x & 1 for x in nums]
        ev = par.count(0)
        od = n - ev
        best = None
        def cost(start_par):
            # start_par is the parity occupying index 0
            pos = [i for i in range(n) if par[i] == start_par]
            targets = list(range(0, n, 2))
            if len(pos) != len(targets):
                return None
            return sum(abs(p - t) for p, t in zip(pos, targets))
        for sp in (0, 1):
            c = cost(sp)
            if c is not None:
                best = c if best is None else min(best, c)
        return -1 if best is None else best

