class Solution:
    def minSwaps(self, nums):
        n = len(nums)
        even_pos = [i for i, x in enumerate(nums) if x % 2 == 0]
        odd_pos = [i for i, x in enumerate(nums) if x % 2 == 1]
        e, o = len(even_pos), len(odd_pos)
        if abs(e - o) > 1:
            return -1
        def assign(group, first_slot):
            return sum(abs(p - t) for p, t in zip(group, range(first_slot, n, 2)))
        res = None
        if e >= o:
            res = assign(even_pos, 0)
        if o >= e:
            c = assign(odd_pos, 0)
            res = c if res is None else min(res, c)
        return res

