var minSwaps = function(nums) {
    const n = nums.length;
    const evenPos = [], oddPos = [];
    for (let i = 0; i < n; i++) {
        if (nums[i] % 2 === 0) evenPos.push(i); else oddPos.push(i);
    }
    const e = evenPos.length, o = oddPos.length;
    if (Math.abs(e - o) > 1) return -1;
    const assign = (group) => {
        let s = 0;
        for (let k = 0; k < group.length; k++) s += Math.abs(group[k] - 2 * k);
        return s;
    };
    let res = null;
    if (e >= o) res = assign(evenPos);
    if (o >= e) {
        const c = assign(oddPos);
        res = res === null ? c : Math.min(res, c);
    }
    return res;
};
